  async query(max_priority: number): Promise<{timeout_: number, fds: Array<GLibPollFD>, return: number}> {
    // Increment ref for parameters with full transfer ownership
    const url = new URL(`${apiConfig.normalizedBasePath}/GLib/MainContext/ptr,${this.ptr}/query`, apiConfig.baseUrl);
    // Primitive parameter
    url.searchParams.append('max_priority', String(max_priority));
    try {
      // Auto-inject correlation ID if we're in a callback context
      const correlationId = getActiveCorrelationId();
      const headers: Record<string, string> = {};
      if (correlationId) {
        headers['X-Correlation-Id'] = correlationId;
      }
      const response = await fetch(url.toString(), Object.keys(headers).length > 0 ? { headers } : undefined);
      if (!response.ok) {
        // If the call fails, unref the objects we ref'd
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const data = await response.json();
        const result: any = {};
      // Handle return parameter: timeout_
      result.timeout_ = await (async () => {
        return data.timeout_;

      })();
      // Handle return parameter: fds
      result.fds = await (async () => {
        if (data.fds && Array.isArray(data.fds)) {
          // Array of objects/structs - instantiate each element using async create()
          const result = await Promise.all(data.fds.map(async (item: any) => {
            if (item && typeof item === 'object' && 'ptr' in item) {
              if (item.ptr === null) {
                return null;
              }
              return await GLibPollFD.create(item.ptr, 'none');
            }
            return item;
          }));
          return result;
        }
        return Promise.reject("Call failed");
      })();
      // Handle return parameter: return
      result.return = await (async () => {
        return data.return;

      })();
      return result;

    } catch (error) {
      // If there's an error, unref the objects we ref'd
      throw error;
    }
  }

    







 
